SELECT * FROM haosen_project..md_fuzzy_match_batch


        AND batch_id = #{batchId}


        AND status = #{status}


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


ORDER BY create_time DESC

SELECT batch_id, id, original_province, original_name, original_address, keyid, name, remark, create_time, update_time FROM haosen_project..md_fuzzy_match_summary
AND batch_id = #{batchId}
AND id = #{originalId}
AND original_province = #{originalProvince}
AND original_name LIKE CONCAT('%', #{originalName}, '%')
AND original_address LIKE CONCAT('%', #{originalAddress}, '%')
AND keyid = #{keyid}
AND name LIKE CONCAT('%', #{name}, '%')
ORDER BY create_time DESC

SELECT keyid, name
FROM HospitalInfo..hospital
WHERE status = 1

    AND province = #{province}

AND name LIKE #{namePattern}

SELECT keyid, name FROM HospitalInfo..hospital WHERE status = 1
AND province = #{province}
AND (name LIKE #{namePattern} OR namehistory LIKE #{namePattern})

SELECT key_id, name FROM HospitalInfo..company WHERE status = 1
AND province = #{province}
AND (name LIKE #{namePattern} OR history_name LIKE #{namePattern})

SELECT key_id, name
FROM HospitalInfo..company
WHERE status = 1

    AND province = #{province}

AND name LIKE #{namePattern}
